#!/usr/bin/env python3
# -*- coding: utf-8 -*-

# Author: Ximan Ding
# Script: 19_plot_depth_sensitivity.py
# Description:
#     Create publication-ready figures for the sequencing-depth sensitivity
#     analysis generated by 18_run_depth_sensitivity.py.
#
#     This script:
#     1. Reads the combined depth-sensitivity result tables;
#     2. Validates required metrics, depths and methods;
#     3. Plots absolute performance across sequencing depths;
#     4. Plots Random Forest and XGBoost improvement over Raw shallow RA;
#     5. Plots shallow-zero recovery across depths;
#     6. Plots abundance-stratum recovery across depths;
#     7. Plots validation performance and XGBoost model-selection results;
#     8. Exports each figure as PDF, PNG and SVG.
#
# Inputs:
#     results/depth_sensitivity/03_depth_sample_level_metrics.csv
#     results/depth_sensitivity/04_depth_performance_summary.csv
#     results/depth_sensitivity/05_depth_abundance_stratum_metrics.csv
#     results/depth_sensitivity/06_depth_zero_recovery_metrics.csv
#     results/depth_sensitivity/07_depth_model_selection_summary.csv
#     results/depth_sensitivity/08_depth_improvement_vs_raw.csv
#
# Outputs:
#     results/figures/depth_sensitivity/
#         Figure10_depth_performance_curves.pdf/png/svg
#         Figure11_depth_improvement_over_raw.pdf/png/svg
#         Figure12_depth_zero_recovery.pdf/png/svg
#         Figure13_depth_abundance_strata.pdf/png/svg
#         Figure14_depth_model_selection.pdf/png/svg
#
# Notes:
#     - The figure numbers can be renamed later when the final report order is
#       fixed.
#     - No model fitting is performed in this script.
#     - The 2,000-read sensitivity result is an independently resimulated and
#       refitted experiment, so it need not exactly match the main analysis.

from __future__ import annotations

from pathlib import Path
import warnings

import matplotlib.pyplot as plt
import numpy as np
import pandas as pd


warnings.filterwarnings("ignore")


# =============================================================================
# 1. Project paths
# =============================================================================

PROJECT_ROOT = Path(__file__).resolve().parents[1]

RESULTS_DIR = PROJECT_ROOT / "results"
DEPTH_RESULTS_DIR = RESULTS_DIR / "depth_sensitivity"
FIGURE_DIR = RESULTS_DIR / "figures" / "depth_sensitivity"

SAMPLE_LEVEL_FILE = (
    DEPTH_RESULTS_DIR / "03_depth_sample_level_metrics.csv"
)
PERFORMANCE_SUMMARY_FILE = (
    DEPTH_RESULTS_DIR / "04_depth_performance_summary.csv"
)
ABUNDANCE_FILE = (
    DEPTH_RESULTS_DIR / "05_depth_abundance_stratum_metrics.csv"
)
ZERO_RECOVERY_FILE = (
    DEPTH_RESULTS_DIR / "06_depth_zero_recovery_metrics.csv"
)
MODEL_SELECTION_FILE = (
    DEPTH_RESULTS_DIR / "07_depth_model_selection_summary.csv"
)
IMPROVEMENT_FILE = (
    DEPTH_RESULTS_DIR / "08_depth_improvement_vs_raw.csv"
)

FIGURE_DIR.mkdir(parents=True, exist_ok=True)


# =============================================================================
# 2. Plot settings
# =============================================================================

EXPECTED_DEPTHS = [500, 1000, 2000, 5000]

METHOD_ORDER = [
    "Raw shallow RA",
    "Training-mean RA",
    "Random Forest",
    "XGBoost",
]

