def plot_improvement_over_raw(
    improvement: pd.DataFrame,
) -> None:
    """Plot percentage improvement of RF and XGBoost over Raw shallow RA."""
    print_step("Step 3: Plot model improvement over Raw shallow RA")

    figure, axes = plt.subplots(
        2,
        3,
        figsize=(14.5, 8.8),
        constrained_layout=True,
    )

    panel_labels = list("ABCDEF")

    for axis, panel_label, (
        metric,
        title,
    ) in zip(
        axes.flat,
        panel_labels,
        IMPROVEMENT_METRICS,
    ):
        current = improvement.loc[
            improvement["metric"] == metric
        ].copy()

        if current.empty:
            raise ValueError(
                f"No improvement rows found for metric: {metric}"
            )

        for model in MODEL_ORDER:
            model_data = current.loc[
                current["model"] == model
            ].sort_values("depth")

            if model_data.empty:
                continue

            axis.plot(
                model_data["depth"],
                model_data["relative_improvement_percent"],
                marker="o",
                linewidth=1.8,
                markersize=5,
                label=METHOD_LABELS[model],
            )

        axis.axhline(
            0.0,
            linestyle="--",
            linewidth=1.0,
        )

        axis.set_title(
            title,
            fontsize=11,
            fontweight="bold",
        )
        axis.set_ylabel("Improvement over Raw (%)")
        format_depth_axis(axis)
        set_common_axis_style(axis)
        add_panel_label(axis, panel_label)

    handles, labels = axes[0, 0].get_legend_handles_labels()

    figure.legend(
        handles,
        labels,
        loc="upper center",
        ncol=2,
        frameon=False,
        bbox_to_anchor=(0.5, 1.035),
    )

    figure.suptitle(
        "Figure 11. Model improvement over Raw shallow RA across depths",
        fontsize=15,
        fontweight="bold",
        y=1.075,
    )

    save_figure(
        figure,
        "Figure11_depth_improvement_over_raw",
    )
    plt.close(figure)


