def plot_zero_recovery(
    zero_metrics: pd.DataFrame,
) -> None:
    """Plot zero-record counts and shallow-zero recovery performance."""
    print_step("Step 4: Plot shallow-zero recovery across depths")

    figure, axes = plt.subplots(
        2,
        2,
        figsize=(11.8, 8.4),
        constrained_layout=True,
    )

    # Panel A: number of shallow-zero, reference-positive records
    record_counts = (
        zero_metrics.loc[
            zero_metrics["method"] == "Raw shallow RA",
            ["depth", "number_of_rows"],
        ]
        .drop_duplicates(subset=["depth"])
        .sort_values("depth")
    )

    axes[0, 0].plot(
        record_counts["depth"],
        record_counts["number_of_rows"],
        marker="o",
        linewidth=1.8,
    )
    axes[0, 0].set_title(
        "Shallow-zero, reference-positive records",
        fontsize=11,
        fontweight="bold",
    )
    axes[0, 0].set_ylabel("Number of OTU records")
    format_depth_axis(axes[0, 0])
    set_common_axis_style(axes[0, 0])
    add_panel_label(axes[0, 0], "A")

    # Panel B: RA-scale RMSE
    for method in METHOD_ORDER:
        current = zero_metrics.loc[
            zero_metrics["method"] == method
        ].sort_values("depth")

        if current.empty:
            continue

        axes[0, 1].plot(
            current["depth"],
            current["RMSE_RA"],
            marker="o",
            linewidth=1.8,
            label=METHOD_LABELS[method],
        )

    axes[0, 1].set_title(
        "Zero-recovery RMSE on the RA scale",
        fontsize=11,
        fontweight="bold",
    )
    axes[0, 1].set_ylabel("RMSE (RA)")
    format_depth_axis(axes[0, 1])
    set_common_axis_style(axes[0, 1])
    add_panel_label(axes[0, 1], "B")

    # Panel C: log10-scale RMSE
    for method in METHOD_ORDER:
        current = zero_metrics.loc[
            zero_metrics["method"] == method
        ].sort_values("depth")

        if current.empty:
            continue

        axes[1, 0].plot(
            current["depth"],
            current["RMSE_log10_RA"],
            marker="o",
            linewidth=1.8,
            label=METHOD_LABELS[method],
        )

    axes[1, 0].set_title(
        "Zero-recovery RMSE on the log10 scale",
        fontsize=11,
        fontweight="bold",
    )
    axes[1, 0].set_ylabel("RMSE (log10 RA)")
    format_depth_axis(axes[1, 0])
    set_common_axis_style(axes[1, 0])
    add_panel_label(axes[1, 0], "C")

    # Panel D: positive prediction rate
    for method in METHOD_ORDER:
        current = zero_metrics.loc[
            zero_metrics["method"] == method
        ].sort_values("depth")

        if current.empty:
            continue

        axes[1, 1].plot(
            current["depth"],
            current["positive_prediction_rate"] * 100,
            marker="o",
            linewidth=1.8,
            label=METHOD_LABELS[method],
        )

    axes[1, 1].set_title(
        "Positive prediction rate for shallow zeros",
        fontsize=11,
        fontweight="bold",
    )
    axes[1, 1].set_ylabel("Positive prediction rate (%)")
    axes[1, 1].set_ylim(-3, 103)
    format_depth_axis(axes[1, 1])
    set_common_axis_style(axes[1, 1])
    add_panel_label(axes[1, 1], "D")

    handles, labels = axes[0, 1].get_legend_handles_labels()

    figure.legend(
        handles,
        labels,
        loc="upper center",
        ncol=4,
        frameon=False,
        bbox_to_anchor=(0.5, 1.035),
    )

    figure.suptitle(
        "Figure 12. Shallow-zero recovery across sequencing depths",
        fontsize=15,
        fontweight="bold",
        y=1.075,
    )

    save_figure(
        figure,
        "Figure12_depth_zero_recovery",
    )
    plt.close(figure)


# =============================================================================
# 8. Figure 13: Abundance-stratum recovery
# =============================================================================

def calculate_abundance_improvement(
    abundance_metrics: pd.DataFrame,
    metric: str,
) -> pd.DataFrame:
    """
    Calculate error improvement over Raw within each depth and abundance group.

    Positive percentages indicate that the ML model has lower error than Raw.
    Improvement is undefined when Raw error is zero.
    """
    current = abundance_metrics[
        [
            "depth",
            "method",
            "abundance_group",
            metric,
        ]
    ].copy()

    wide = current.pivot_table(
        index=["depth", "abundance_group"],
        columns="method",
        values=metric,
        aggfunc="first",
    ).reset_index()

    records = []

    for _, row in wide.iterrows():
        if "Raw shallow RA" not in wide.columns:
            continue

        raw_value = row.get("Raw shallow RA", np.nan)

        for model in MODEL_ORDER:
            model_value = row.get(model, np.nan)

            if (
                pd.isna(raw_value)
                or pd.isna(model_value)
                or abs(raw_value) <= 1e-15
            ):
                improvement = np.nan
            else:
                improvement = (
                    (raw_value - model_value)
                    / abs(raw_value)
                    * 100
                )

            records.append(
                {
                    "depth": int(row["depth"]),
                    "abundance_group": row["abundance_group"],
                    "model": model,
                    "metric": metric,
                    "improvement_percent": improvement,
                }
            )

    return pd.DataFrame(records)


def plot_abundance_strata(
    abundance_metrics: pd.DataFrame,
) -> None:
    """Plot abundance-stratum error improvement across sequencing depths."""
    print_step("Step 5: Plot abundance-stratum recovery across depths")

    ra_improvement = calculate_abundance_improvement(
        abundance_metrics,
        "RMSE_RA",
    )

    log_improvement = calculate_abundance_improvement(
        abundance_metrics,
        "RMSE_log10_RA",
    )

    figure, axes = plt.subplots(
        2,
        2,
        figsize=(13.0, 9.2),
        constrained_layout=True,
    )

    plot_specs = [
        (
            axes[0, 0],
            ra_improvement,
            "Random Forest",
            "RF improvement: RA-scale RMSE",
            "A",
        ),
        (
            axes[0, 1],
            ra_improvement,
            "XGBoost",
            "XGBoost improvement: RA-scale RMSE",
            "B",
        ),
        (
            axes[1, 0],
            log_improvement,
            "Random Forest",
            "RF improvement: log10-scale RMSE",
            "C",
        ),
        (
            axes[1, 1],
            log_improvement,
            "XGBoost",
            "XGBoost improvement: log10-scale RMSE",
            "D",
        ),
    ]

    for axis, dataframe, model, title, panel_label in plot_specs:
        model_data = dataframe.loc[
            dataframe["model"] == model
        ].copy()

        for abundance_group in ABUNDANCE_ORDER:
            group_data = model_data.loc[
                model_data["abundance_group"] == abundance_group
            ].sort_values("depth")

            if group_data.empty:
                continue

            if group_data["improvement_percent"].notna().sum() == 0:
                continue

            axis.plot(
                group_data["depth"],
                group_data["improvement_percent"],
                marker="o",
                linewidth=1.6,
                markersize=4.5,
                label=ABUNDANCE_LABELS[abundance_group],
            )

        axis.axhline(
            0.0,
            linestyle="--",
            linewidth=1.0,
        )
        axis.set_title(
            title,
            fontsize=11,
            fontweight="bold",
        )
        axis.set_ylabel("Improvement over Raw (%)")
        format_depth_axis(axis)
        set_common_axis_style(axis)
        add_panel_label(axis, panel_label)

    handles, labels = axes[0, 0].get_legend_handles_labels()

    figure.legend(
        handles,
        labels,
        loc="upper center",
        ncol=5,
        frameon=False,
        bbox_to_anchor=(0.5, 1.035),
    )

    figure.suptitle(
        "Figure 13. Abundance-stratum recovery across sequencing depths",
        fontsize=15,
        fontweight="bold",
        y=1.075,
    )

    save_figure(
        figure,
        "Figure13_depth_abundance_strata",
    )
    plt.close(figure)


# =============================================================================
# 9. Figure 14: Validation and model selection
# =============================================================================

def plot_model_selection(
    model_selection: pd.DataFrame,
) -> None:
    """Plot validation RMSE, selected tree count and runtime by depth."""
    print_step("Step 6: Plot validation performance and model selection")

    current = model_selection.sort_values("depth").copy()

    figure, axes = plt.subplots(
        1,
        3,
        figsize=(14.2, 4.5),
        constrained_layout=True,
    )

    # Panel A: validation RMSE
    axes[0].plot(
        current["depth"],
        current["rf_validation_log_rmse"],
        marker="o",
        linewidth=1.8,
        label="Random Forest",
    )

    axes[0].plot(
        current["depth"],
        current["xgb_validation_log_rmse"],
        marker="o",
        linewidth=1.8,
        label="XGBoost",
    )

    axes[0].set_title(
        "Validation log10-RMSE",
        fontsize=11,
        fontweight="bold",
    )
    axes[0].set_ylabel("Validation log10-RMSE")
    format_depth_axis(axes[0])
    set_common_axis_style(axes[0])
    add_panel_label(axes[0], "A")
    axes[0].legend(frameon=False)

    # Panel B: selected XGBoost tree count
    axes[1].plot(
        current["depth"],
        current["xgb_best_iteration"],
        marker="o",
        linewidth=1.8,
    )

    axes[1].set_title(
        "Selected XGBoost tree count",
        fontsize=11,
        fontweight="bold",
    )
    axes[1].set_ylabel("Best iteration")
    format_depth_axis(axes[1])
    set_common_axis_style(axes[1])
    add_panel_label(axes[1], "B")

    # Panel C: runtime
    axes[2].plot(
        current["depth"],
        current["rf_first_fit_minutes"],
        marker="o",
        linewidth=1.8,
        label="RF first fit",
    )

    axes[2].plot(
        current["depth"],
        current["xgb_first_fit_minutes"],
        marker="o",
        linewidth=1.8,
        label="XGB first fit",
    )

    axes[2].plot(
        current["depth"],
        current["total_depth_minutes"],
        marker="o",
        linewidth=1.8,
        label="Total depth run",
    )

    axes[2].set_title(
        "Model-fitting and total runtime",
        fontsize=11,
        fontweight="bold",
    )
    axes[2].set_ylabel("Runtime (minutes)")
    format_depth_axis(axes[2])
    set_common_axis_style(axes[2])
    add_panel_label(axes[2], "C")
    axes[2].legend(frameon=False)

    figure.suptitle(
        "Figure 14. Validation performance and depth-specific model selection",
        fontsize=15,
        fontweight="bold",
        y=1.06,
    )

    save_figure(
        figure,
        "Figure14_depth_model_selection",
    )
    plt.close(figure)


# =============================================================================
# 10. Main workflow
# =============================================================================

def main() -> None:
    """Run the complete depth-sensitivity plotting workflow."""
    (
        _sample_level,
        performance_summary,
        abundance_metrics,
        zero_metrics,
        model_selection,
        improvement,
    ) = read_inputs()

    plot_depth_performance_curves(
        performance_summary
    )

    plot_improvement_over_raw(
        improvement
    )

    plot_zero_recovery(
        zero_metrics
    )

    plot_abundance_strata(
        abundance_metrics
    )

    plot_model_selection(
        model_selection
    )

    print_step("Depth-sensitivity figures completed")
    print(f"Figure directory: {FIGURE_DIR}")
    print("Generated figure groups:")
    print("  - Figure10_depth_performance_curves")
    print("  - Figure11_depth_improvement_over_raw")
    print("  - Figure12_depth_zero_recovery")
    print("  - Figure13_depth_abundance_strata")
    print("  - Figure14_depth_model_selection")


if __name__ == "__main__":
    main()
